import{_ as i,c as t,o as a,aj as l}from"./chunks/framework.VtnL2jmu.js";const k=JSON.parse('{"title":"Git仓库免密访问","description":"","frontmatter":{},"headers":[],"relativePath":"git/Git仓库免密访问.md","filePath":"git/Git仓库免密访问.md"}'),s={name:"git/Git仓库免密访问.md"};function o(r,e,n,d,h,c){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="git仓库免密访问" tabindex="-1">Git仓库免密访问 <a class="header-anchor" href="#git仓库免密访问" aria-label="Permalink to “Git仓库免密访问”">​</a></h1><h2 id="ssh-密钥-最推荐" tabindex="-1">SSH 密钥（最推荐） <a class="header-anchor" href="#ssh-密钥-最推荐" aria-label="Permalink to “SSH 密钥（最推荐）”">​</a></h2><p>适用于 GitHub、GitLab、Gitee 等，通过密钥对认证。</p><ul><li>生成密钥：<code>ssh-keygen -t rsa -b 4096 -C &quot;your_email@example.com&quot;</code></li><li>添加公钥：将 <code>~/.ssh/id_rsa.pub</code> 内容复制到 Git 平台（Settings → SSH Keys）。</li><li>使用 SSH 地址：克隆时用 <code>git@github.com:用户名/仓库.git</code>，而不是 <code>https://</code> 开头的地址。</li></ul><h2 id="credential-helper-https-长期缓存" tabindex="-1">credential.helper（HTTPS 长期缓存） <a class="header-anchor" href="#credential-helper-https-长期缓存" aria-label="Permalink to “credential.helper（HTTPS 长期缓存）”">​</a></h2><p>适合个人电脑，缓存账号密码或 Token。</p><ul><li>永久存储：<code>git config --global credential.helper store</code>（下次输入后明文保存，慎用）。</li><li>缓存一段时间：<code>git config --global credential.helper &#39;cache --timeout=3600&#39;</code>（缓存 1 小时）。</li><li>Windows/macOS 会自动使用系统凭据管理器（钥匙串/凭据管理器），通常无需配置。</li></ul><h2 id="个人访问令牌-token" tabindex="-1">个人访问令牌（Token） <a class="header-anchor" href="#个人访问令牌-token" aria-label="Permalink to “个人访问令牌（Token）”">​</a></h2><p>当平台禁用密码登录时（如 GitHub），用 Token 代替密码。</p><ul><li>在 Git 平台生成 Token（勾选 <code>repo</code>、<code>workflow</code> 等权限）。</li><li>执行 <code>git push</code> 时，用户名不变，密码处粘贴 Token。</li><li>配合 <code>credential.helper</code>，首次输入后自动保存。</li></ul><p>已用 HTTPS 但想切 SSH：修改远程地址为 SSH 格式。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com:用户名/仓库.git</span></span></code></pre></div><p>安全提醒：多因素认证环境下，Token 比密码更安全；使用 <code>store</code> 时确保电脑不会被他人使用。</p>',13)])])}const g=i(s,[["render",o]]);export{k as __pageData,g as default};
